import os
import requests


def download_physionet_file(base_url, filename, save_dir="."):
    """
    从 PhysioNet 下载指定文件
    """
    # 确保保存目录存在
    os.makedirs(save_dir, exist_ok=True)

    url = f"{base_url}{filename}"
    save_path = os.path.join(save_dir, filename)

    print(f"正在请求下载: {url}")

    # 使用 stream=True 支持大文件下载
    try:
        response = requests.get(url, stream=True)
        response.raise_for_status()  # 检查请求是否成功

        # 获取文件大小以便显示进度（可选）
        total_size = int(response.headers.get('content-length', 0))
        downloaded_size = 0

        with open(save_path, 'wb') as f:
            for chunk in response.iter_content(chunk_size=8192):
                if chunk:
                    f.write(chunk)
                    downloaded_size += len(chunk)
                    # 打印简单的下载进度
                    if total_size > 0:
                        percent = int(50 * downloaded_size / total_size)
                        print(f"\r[{'=' * percent}{' ' * (50 - percent)}] {downloaded_size}/{total_size} Bytes", end="")

        print(f"\n下载完成: {save_path}\n")

    except requests.exceptions.RequestException as e:
        print(f"\n下载失败 {filename}: {e}")


